import app from 'flarum/forum/app';
import { extend } from 'flarum/common/extend';
import SessionDropdown from 'flarum/forum/components/SessionDropdown';
import DiscussionPage from 'flarum/forum/components/DiscussionPage';
import LinkButton from 'flarum/common/components/LinkButton';
import CharactersPage from './components/CharactersPage';
import DeckPage from './components/DeckPage';
import CombatTracker from './components/CombatTracker';
import inCharacter from './inCharacter';
import composerPicker from './composerPicker';
import { isRpDiscussion } from './rpTags';
app.initializers.add('ernestdefoe-roleplay', () => {
  app.routes['rp.characters'] = {
    path: '/characters',
    component: CharactersPage
  };
  app.routes['rp.deck'] = {
    path: '/deck',
    component: DeckPage
  };

  // "My Characters" + "My Deck" entries in the account dropdown.
  extend(SessionDropdown.prototype, 'items', function (items) {
    if (!app.session.user) return;
    items.add('rp-characters', LinkButton.component({
      href: app.route('rp.characters'),
      icon: 'fas fa-dragon'
    }, app.translator.trans('ernestdefoe-roleplay.forum.my_characters')), 50);
    items.add('rp-deck', LinkButton.component({
      href: app.route('rp.deck'),
      icon: 'fas fa-layer-group'
    }, app.translator.trans('ernestdefoe-roleplay.forum.my_deck')), 49);
  });

  // The combat tracker lives at the top of a discussion's sidebar — but only in
  // discussions where role-play is enabled (admin-configured tags).
  extend(DiscussionPage.prototype, 'sidebarItems', function (items) {
    const discussion = this.discussion;
    if (!discussion || !isRpDiscussion(discussion)) return;
    items.add('rp-combat', CombatTracker.component({
      discussionId: Number(discussion.id())
    }), 100);
  });
  inCharacter();
  composerPicker();
});